static void uf_union(int a,int b){ a=uf_find(a); b=uf_find(b); if(a!=b) par[b]=a; }
int accountsMerge(char*** accounts, int n, int* cs, char**** ret, int* rs, int** rcs) {
    for(int i=0;i<n;i++) par[i]=i;
    char email[1000][64]; int owner[1000], ec=0;
